mapper.sql:
FROM ( SELECT IOTYPE , IBHDTYPE , CTKEY , OWKEY , ICKEY , ICGRKEY , LOGGRPCD , IN_QTY , STOCK_QTY , OUT_QTY , IBCONFIRMDATE , IVATKEY , ATTRIBUTE3 , PRODUCTLOT , SPEC , UOM , PRODUCTDATE , EXPIREDATE , IBEXPECTDATE , ATTRIBUTE7 , LCKEY , ARKEY , ARNAME , ZNNAME FROM ( /* 입고 */ SELECT 'IB' AS IOTYPE , TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.IVATKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.IBHDTYPE , TO1.IBCONFIRMDATE , TO1.CFQTY AS IN_QTY , 0 AS STOCK_QTY , 0 AS OUT_QTY , TO1.ATTRIBUTE3 , TO1.PRODUCTLOT , TO1.SPEC , TO1.UOM , TO1.PRODUCTDATE , TO1.EXPIREDATE , TO1.IBEXPECTDATE , TO1.ATTRIBUTE7 , TO1.LCKEY , '' AS ARKEY , '' AS ARNAME , '' AS ZNNAME FROM ( SELECT T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.IBHDTYPE , T1.IBCONFIRMDATE , SUM(T1.CFQTY) AS CFQTY , T1.ATTRIBUTE3 , T1.PRODUCTLOT , T1.SPEC , T1.UOM , T1.PRODUCTDATE , T1.EXPIREDATE , T1.IBEXPECTDATE , T1.ATTRIBUTE7 , T1.LCKEY FROM ( SELECT B.CTKEY , B.OWKEY , C.ICKEY , F.IVATKEY , E.LOGGRPCD , E.ICGRKEY , B.IBHDTYPE , COALESCE(CAST(D.CFQTY AS NUMERIC), 0) AS CFQTY , F.IBCONFIRMDATE , F.ATTRIBUTE3 , F.PRODUCTLOT , E.SPEC , C.UOM , F.PRODUCTDATE , F.EXPIREDATE , B.IBEXPECTDATE , F.ATTRIBUTE7 , C.TO_LCKEY AS LCKEY FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_INFO_IBCF_DT D ON C.CTKEY = D.CTKEY AND C.EXTERNORDERKEY = D.EXTERNORDERKEY AND C.EXTERNORDERLINENUM = D.EXTERNORDERLINENUM INNER JOIN TWORK_MST_IC E ON C.CTKEY = E.CTKEY AND C.OWKEY = E.OWKEY AND C.ICKEY = E.ICKEY INNER JOIN TWORK_INFO_IVAT F ON C.CTKEY = F.CTKEY AND C.ICKEY = F.ICKEY AND D.TO_IVATKEY = F.IVATKEY WHERE B.IBHDTYPE IN ('10', '40') /* 일반입고와 보세입고 */ AND C.WKSTATUS IN ('90', '91')
UNION ALL
SELECT B.CTKEY , B.OWKEY , C.ICKEY , F.IVATKEY AS IVATKEY , D.LOGGRPCD , D.ICGRKEY , B.IBHDTYPE , COALESCE(C.CFQTY, 0) AS CFQTY , F.IBCONFIRMDATE , F.ATTRIBUTE3 , F.PRODUCTLOT , D.SPEC , D.UOM , F.PRODUCTDATE , F.EXPIREDATE , B.IBEXPECTDATE , F.ATTRIBUTE7 , C.TO_LCKEY AS LCKEY FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY INNER JOIN TWORK_INFO_IVAT F ON B.CTKEY = F.CTKEY AND C.ICKEY = F.ICKEY AND C.TO_IVATKEY = F.IVATKEY WHERE B.IBHDTYPE NOT IN ('10', '40') /* 일반입고와 보세입고 제외한 나머지 */ AND C.WKSTATUS IN ('90', '91') ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.IBHDTYPE , T1.IBCONFIRMDATE , T1.ATTRIBUTE3 , T1.PRODUCTLOT , T1.SPEC , T1.UOM , T1.PRODUCTDATE , T1.EXPIREDATE , T1.IBEXPECTDATE , T1.ATTRIBUTE7 , T1.LCKEY ) TO1
UNION ALL
/* 적치 */ SELECT 'ST' AS IOTYPE , ST.CTKEY , ST.OWKEY , ST.ICKEY , ST.IVATKEY , ST.LOGGRPCD , ST.ICGRKEY , ST.IVHSTYPE , ST.STCONFIRMDATE , 0 AS IN_QTY , ST.CFQTY AS STOCK_QTY , 0 AS OUT_QTY , ST.ATTRIBUTE3 , ST.PRODUCTLOT , ST.SPEC , ST.UOM , ST.PRODUCTDATE , ST.EXPIREDATE , '' AS IBEXPECTDATE , ST.ATTRIBUTE7 , ST.LCKEY , ST.ARKEY , ST.ARNAME , ST.ZNNAME FROM ( SELECT T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.IVHSTYPE , T1.STCONFIRMDATE , SUM(T1.CFQTY) AS CFQTY , T1.ATTRIBUTE3 , T1.PRODUCTLOT , T1.SPEC , T1.UOM , T1.PRODUCTDATE , T1.EXPIREDATE , T1.ATTRIBUTE7 , T1.LCKEY , T1.ARKEY , T1.ARNAME , T1.ZNNAME FROM ( SELECT TB1.CTKEY , TB1.OWKEY , TB1.ICKEY , TB1.IVATKEY , TB1.LOGGRPCD , TB2.ICGRKEY , TB1.IVHSTYPE , COALESCE(CAST(TB1.QTY AS NUMERIC), 0) AS CFQTY , SUBSTR(TB1.INSERTDATE, 1, 8) || '000000' AS STCONFIRMDATE , TB1.ATTRIBUTE3 , TB1.PRODUCTLOT , TB2.SPEC , TB2.UOM , TB1.PRODUCTDATE , TB3.EXPIREDATE , TB3.ATTRIBUTE7 , TB1.TO_LCKEY AS LCKEY , TB4.ARKEY , TB5.ARNAME , TB6.ZNNAME FROM TWORK_INFO_IVHS TB1 INNER JOIN ( SELECT CTKEY , OWKEY , ICKEY , IVATKEY , ATTRIBUTE3 , PRODUCTLOT , TO_ULCKEY , MIN(INSERTDATE) AS INSERTDATE_MIN , MIN(IVHSKEY) IVHSKEY FROM TWORK_INFO_IVHS WHERE IVHSTYPE = '60' GROUP BY CTKEY , OWKEY , ICKEY , IVATKEY , ATTRIBUTE3 , PRODUCTLOT , TO_ULCKEY ORDER BY IVATKEY ) TB7 ON TB1.CTKEY = TB7.CTKEY AND TB1.OWKEY = TB7.OWKEY AND TB1.IVHSKEY = TB7.IVHSKEY INNER JOIN TWORK_MST_IC TB2 ON TB1.CTKEY = TB2.CTKEY AND TB1.OWKEY = TB2.OWKEY AND TB1.ICKEY = TB2.ICKEY INNER JOIN TWORK_INFO_IVAT TB3 ON TB1.CTKEY = TB3.CTKEY AND TB1.OWKEY = TB3.OWKEY AND TB1.IVATKEY = TB3.IVATKEY INNER JOIN TWORK_MST_LC TB4 ON TB1.CTKEY = TB4.CTKEY AND TB1.TO_LCKEY = TB4.LCKEY INNER JOIN TWORK_MST_AR TB5 ON TB4.CTKEY = TB5.CTKEY AND TB4.ARKEY = TB5.ARKEY INNER JOIN TWORK_MST_ZN TB6 ON TB5.CTKEY = TB6.CTKEY AND TB5.ZNKEY = TB6.ZNKEY WHERE TB1.IVHSTYPE IN ('60') /* 일반입고와 보세입고로 들어온 재고 적치 */ ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.IVHSTYPE , T1.STCONFIRMDATE , T1.ATTRIBUTE3 , T1.PRODUCTLOT , T1.SPEC , T1.UOM , T1.PRODUCTDATE , T1.EXPIREDATE , T1.ATTRIBUTE7 , T1.LCKEY , T1.ARKEY , T1.ARNAME , T1.ZNNAME ) ST
UNION ALL
/* 출고 */ SELECT 'OB' AS IOTYPE , T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.OBHDTYPE , T1.OBCONFIRMDATE , 0 IN_QTY , 0 STOCK_QTY , SUM(T1.CFQTY) AS OUT_QTY , T1.ATTRIBUTE3 , T1.PRODUCTLOT , T1.SPEC , T1.UOM , T1.PRODUCTDATE , T1.EXPIREDATE , T1.OBREQUESTDATE , T1.ATTRIBUTE7 , T1.LCKEY , T1.ARKEY , T1.ARNAME , T1.ZNNAME FROM ( SELECT A.CTKEY , A.OWKEY , B.ICKEY , F.IVATKEY , C.LOGGRPCD , C.ICGRKEY , A.OBHDTYPE , COALESCE(D.CFQTY, 0) AS CFQTY , B.OBCONFIRMDATE , F.ATTRIBUTE3 , F.PRODUCTLOT , C.SPEC , B.UOM , F.PRODUCTDATE , F.EXPIREDATE , A.OBREQUESTDATE , F.ATTRIBUTE7 , D.LCKEY , G.ARKEY , H.ARNAME , I.ZNNAME FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICKEY = C.ICKEY INNER JOIN TWORK_INFO_PI_DT D ON B.CTKEY = D.CTKEY AND B.OWKEY = D.OWKEY AND B.ICKEY = D.ICKEY AND B.OBHDKEY = D.OBHDKEY AND B.OBDTKEY = D.OBDTKEY INNER JOIN TWORK_INFO_IVAT F ON A.CTKEY = F.CTKEY AND B.ICKEY = F.ICKEY AND D.IVATKEY = F.IVATKEY AND D.ICKEY = F.ICKEY LEFT OUTER JOIN TWORK_MST_LC G ON D.CTKEY = G.CTKEY AND D.LCKEY = G.LCKEY LEFT OUTER JOIN TWORK_MST_AR H ON G.CTKEY = H.CTKEY AND G.ARKEY = H.ARKEY LEFT OUTER JOIN TWORK_MST_ZN I ON H.CTKEY = I.CTKEY AND H.ZNKEY = I.ZNKEY WHERE B.WKSTATUS IN ('90', '91') AND A.OBHDTYPE = '10'
UNION ALL
SELECT A.CTKEY , A.OWKEY , B.ICKEY , F.IVATKEY , C.LOGGRPCD , C.ICGRKEY , A.OBHDTYPE , COALESCE(D.CFQTY, 0) AS CFQTY , B.OBCONFIRMDATE , F.ATTRIBUTE3 , F.PRODUCTLOT , C.SPEC , B.UOM , F.PRODUCTDATE , F.EXPIREDATE , A.OBREQUESTDATE , F.ATTRIBUTE7 , D.LCKEY , G.ARKEY , H.ARNAME , I.ZNNAME FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICKEY = C.ICKEY INNER JOIN TWORK_INFO_PI_DT D ON B.CTKEY = D.CTKEY AND B.OWKEY = D.OWKEY AND B.ICKEY = D.ICKEY AND B.OBHDKEY = D.OBHDKEY AND B.OBDTKEY = D.OBDTKEY INNER JOIN TWORK_INFO_IVAT F ON A.CTKEY = F.CTKEY AND B.ICKEY = F.ICKEY AND D.IVATKEY = F.IVATKEY LEFT OUTER JOIN TWORK_MST_LC G ON D.CTKEY = G.CTKEY AND D.LCKEY = G.LCKEY LEFT OUTER JOIN TWORK_MST_AR H ON G.CTKEY = H.CTKEY AND G.ARKEY = H.ARKEY LEFT OUTER JOIN TWORK_MST_ZN I ON H.CTKEY = I.CTKEY AND H.ZNKEY = I.ZNKEY WHERE B.WKSTATUS IN ('90', '91') AND A.OBHDTYPE != '10' ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.OBHDTYPE , T1.OBCONFIRMDATE , T1.ATTRIBUTE3 , T1.PRODUCTLOT , T1.SPEC , T1.UOM , T1.PRODUCTDATE , T1.EXPIREDATE , T1.OBREQUESTDATE , T1.ATTRIBUTE7 , T1.LCKEY , T1.ARKEY , T1.ARNAME , T1.ZNNAME ) A ) X INNER JOIN TWORK_MST_CT A ON X.CTKEY = A.CTKEY INNER JOIN TWORK_MST_OW B ON X.OWKEY = B.OWKEY INNER JOIN TWORK_MST_IC C ON X.CTKEY = C.CTKEY AND X.OWKEY = C.OWKEY AND X.ICKEY = C.ICKEY INNER JOIN TWORK_MST_ICGR D ON X.CTKEY = D.CTKEY AND X.OWKEY = D.OWKEY AND X.ICGRKEY = D.ICGRKEY INNER JOIN TWORK_MST_LC E ON X.CTKEY = E.CTKEY AND X.LCKEY = E.LCKEY INNER JOIN TWORK_MST_AR F ON E.CTKEY = F.CTKEY AND E.ARKEY = F.ARKEY INNER JOIN TWORK_MST_ZN G ON F.CTKEY = G.CTKEY AND F.ZNKEY = G.ZNKEY
AND #{SEARCH_CONDITION}

mapper.select:
#{GRIDPAGING_ROWNUMTYPE_TOP}




			ORDER BY #{colName} DESC


			ORDER BY #{colName} ASC



			ORDER BY X.IBCONFIRMDATE, X.OWNAME, X.ICNAME


#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

SELECT SUM(IN_QTY) AS IN_QTY, SUM(OUT_QTY) AS OUT_QTY
  FROM (

  )
